record_types.code:
type a_Shape (Kind : shape_Kind := Cube) is
   record
      case Kind
      is
         when Cube | Cylinder =>
            half_Extents  :        Vector_3;
         when a_Capsule =>
            lower_Radius,
            upper_Radius  :        Real;
            Height        :        Real;
         when Heightfield =>
            Heights       : access physics.Heightfield;
            height_Range  :        Vector_2;
         when a_Sphere =>
            sphere_Radius :        Real;
         when Circle =>
            circle_Radius :        Real;
         when Hull =>
            Points        : access physics.Vector_3_array;
         when Mesh =>
            Model         : access Geometry_3D.a_Model;
         when multi_Sphere =>
            Sites         : access physics.Vector_3_array;
            Radii         : access Vector;
         when Plane =>
            plane_Normal  :        Vector_3;
            plane_Offset  :        Real;
         when Polygon =>
            Vertices      :        Geometry_2d.Sites (1 .. 8);
            vertex_Count  :        Natural := 0;
         when others =>
            null;
      end case;
   end record;

tagged_types.code:
type Item is new physics.remote.Model.item with
   record
      shape_Info  : a_Shape;
      Shape       : physics.Shape.view;
      Mass        : Real;
      Friction    : Real;
      Restitution : Real;
      is_Tangible : Boolean := True;
   end record;
